  1→type Token =
  2→  | {
  3→      type: 'number';
  4→      value: number;
  5→    }
  6→  | {
  7→      type: 'op';
  8→      value: string;
  9→    }
 10→  | {
 11→      type: 'paren';
 12→      value: '(' | ')';
 13→    }
 14→  | {
 15→      type: 'func';
 16→      value: string;
 17→    };
 18→
 19→const FUNCTIONS: Record<string, (n: number) => number> = {
 20→  sqrt: Math.sqrt,
 21→  abs: Math.abs,
 22→  sin: Math.sin,
 23→  cos: Math.cos,
 24→  tan: Math.tan,
 25→  log: Math.log10,
 26→  ln: Math.log,
 27→  ceil: Math.ceil,
 28→  floor: Math.floor,
 29→  round: Math.round,
 30→  exp: Math.exp,
 31→};
 32→
 33→const CONSTANTS: Record<string, number> = {
 34→  pi: Math.PI,
 35→  e: Math.E,
 36→};
 37→
 38→function tokenize(input: string): Token[] | null {
 39→  const tokens: Token[] = [];
 40→  let i = 0;
 41→  const s = input.replace(/\s+/g, '');
 42→
 43→  while (i < s.length) {
 44→    const ch = s[i]!;
 45→
 46→    if ((ch >= '0' && ch <= '9') || ch === '.') {
 47→      let num = '';
 48→      while (i < s.length && ((s[i]! >= '0' && s[i]! <= '9') || s[i] === '.')) {
 49→        num += s[i];
 50→        i++;
 51→      }
 52→      const parsed = parseFloat(num);
 53→      if (isNaN(parsed)) return null;
 54→      tokens.push({
 55→        type: 'number',
 56→        value: parsed,
 57→      });
 58→      continue;
 59→    }
 60→
 61→    if ((ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z')) {
 62→      let word = '';
 63→      while (
 64→        i < s.length &&
 65→        ((s[i]! >= 'a' && s[i]! <= 'z') || (s[i]! >= 'A' && s[i]! <= 'Z'))
 66→      ) {
 67→        word += s[i];
 68→        i++;
 69→      }
 70→      const lower = word.toLowerCase();
 71→      if (CONSTANTS[lower] !== undefined) {
 72→        tokens.push({
 73→          type: 'number',
 74→          value: CONSTANTS[lower],
 75→        });
 76→      } else if (FUNCTIONS[lower]) {
 77→        tokens.push({
 78→          type: 'func',
 79→          value: lower,
 80→        });
 81→      } else {
 82→        return null;
 83→      }
 84→      continue;
 85→    }
 86→
 87→    if (ch === '(' || ch === ')') {
 88→      tokens.push({
 89→        type: 'paren',
 90→        value: ch,
 91→      });
 92→      i++;
 93→      continue;
 94→    }
 95→
 96→    if (ch === '+' || ch === '-' || ch === '*' || ch === '/' || ch === '^') {
 97→      tokens.push({
 98→        type: 'op',
 99→        value: ch,
100→      });
101→      i++;
102→      continue;
103→    }
104→
105→    if (ch === '%') {
106→      tokens.push({
107→        type: 'op',
108→        value: '%',
109→      });
110→      i++;
111→      continue;
112→    }
113→
114→    return null;
115→  }
116→
117→  return tokens.length > 0 ? tokens : null;
118→}
119→
120→function precedence(op: string): number {
121→  if (op === '+' || op === '-') return 1;
122→  if (op === '*' || op === '/' || op === '%') return 2;
123→  if (op === '^') return 3;
124→  return 0;
125→}
126→
127→function applyOp(op: string, a: number, b: number): number | null {
128→  switch (op) {
129→    case '+':
130→      return a + b;
131→    case '-':
132→      return a - b;
133→    case '*':
134→      return a * b;
135→    case '/':
136→      return b === 0 ? null : a / b;
137→    case '%':
138→      return (a * b) / 100;
139→    case '^':
140→      return Math.pow(a, b);
141→    default:
142→      return null;
143→  }
144→}
145→
146→function parse(tokens: Token[]): number | null {
147→  let pos = 0;
148→
149→  function parseExpression(minPrec: number): number | null {
150→    let left = parseUnary();
151→    if (left === null) return null;
152→
153→    while (pos < tokens.length) {
154→      const token = tokens[pos]!;
155→      if (token.type !== 'op') break;
156→
157→      const prec = precedence(token.value);
158→      if (prec < minPrec) break;
159→
160→      pos++;
161→      const right = parseExpression(token.value === '^' ? prec : prec + 1);
162→      if (right === null) return null;
163→
164→      const result = applyOp(token.value, left, right);
165→      if (result === null) return null;
166→      left = result;
167→    }
168→
169→    return left;
170→  }
171→
172→  function parseUnary(): number | null {
173→    const token = tokens[pos];
174→    if (!token) return null;
175→
176→    if (token.type === 'op' && token.value === '-') {
177→      pos++;
178→      const val = parseUnary();
179→      return val === null ? null : -val;
180→    }
181→
182→    if (token.type === 'op' && token.value === '+') {
183→      pos++;
184→      return parseUnary();
185→    }
186→
187→    return parsePrimary();
188→  }
189→
190→  function parsePrimary(): number | null {
191→    const token = tokens[pos];
192→    if (!token) return null;
193→
194→    if (token.type === 'number') {
195→      pos++;
196→      return token.value;
197→    }
198→
199→    if (token.type === 'func') {
200→      const fn = FUNCTIONS[token.value];
201→      if (!fn) return null;
202→      pos++;
203→      if (
204→        pos >= tokens.length ||
205→        tokens[pos]!.type !== 'paren' ||
206→        tokens[pos]!.value !== '('
207→      ) {
208→        return null;
209→      }
210→      pos++;
211→      const arg = parseExpression(0);
212→      if (arg === null) return null;
213→      if (
214→        pos >= tokens.length ||
215→        tokens[pos]!.type !== 'paren' ||
216→        tokens[pos]!.value !== ')'
217→      ) {
218→        return null;
219→      }
220→      pos++;
221→      return fn(arg);
222→    }
223→
224→    if (token.type === 'paren' && token.value === '(') {
225→      pos++;
226→      const val = parseExpression(0);
227→      if (val === null) return null;
228→      if (
229→        pos >= tokens.length ||
230→        tokens[pos]!.type !== 'paren' ||
231→        tokens[pos]!.value !== ')'
232→      ) {
233→        return null;
234→      }
235→      pos++;
236→      return val;
237→    }
238→
239→    return null;
240→  }
241→
242→  const result = parseExpression(0);
243→  if (result === null || pos !== tokens.length) return null;
244→  return result;
245→}
246→
247→function looksLikeMathExpression(input: string): boolean {
248→  const trimmed = input.trim();
249→  if (!trimmed) return false;
250→  if (/^[a-zA-Z]+$/.test(trimmed)) return false;
251→  if (/[+\-*/^%]/.test(trimmed) || /\d/.test(trimmed)) return true;
252→  return false;
253→}
254→
255→export function formatResult(value: number): string {
256→  if (!isFinite(value)) return String(value);
257→  if (Number.isInteger(value)) return value.toLocaleString('en-US');
258→  const fixed = value.toFixed(10);
259→  const trimmed = fixed.replace(/0+$/, '').replace(/\.$/, '');
260→  const parts = trimmed.split('.');
261→  if (parts.length === 2 && parts[1]!.length > 6) {
262→    return value.toFixed(6).replace(/0+$/, '').replace(/\.$/, '');
263→  }
264→  return trimmed;
265→}
266→
267→export function evaluate(input: string): string | null {
268→  const trimmed = input.trim();
269→  if (!looksLikeMathExpression(trimmed)) return null;
270→
271→  const tokens = tokenize(trimmed);
272→  if (!tokens) return null;
273→
274→  const hasOperatorOrFunc = tokens.some(
275→    t => t.type === 'op' || t.type === 'func',
276→  );
277→  if (!hasOperatorOrFunc) return null;
278→
279→  const result = parse(tokens);
280→  if (result === null || !isFinite(result)) return null;
281→
282→  return formatResult(result);
283→}
